// HasConfig applies the HasEdge predicate on the "config" edge.
func HasConfig() predicate.UpstreamBalanceSnapshot {
	return predicate.UpstreamBalanceSnapshot(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, ConfigTable, ConfigColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasConfigWith applies the HasEdge predicate on the "config" edge with a given conditions (other predicates).
func HasConfigWith(preds ...predicate.UpstreamConfig) predicate.UpstreamBalanceSnapshot {
	return predicate.UpstreamBalanceSnapshot(func(s *sql.Selector) {
		step := newConfigStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasRun applies the HasEdge predicate on the "run" edge.
func HasRun() predicate.UpstreamBalanceSnapshot {
	return predicate.UpstreamBalanceSnapshot(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, RunTable, RunColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasRunWith applies the HasEdge predicate on the "run" edge with a given conditions (other predicates).
func HasRunWith(preds ...predicate.UpstreamSyncRun) predicate.UpstreamBalanceSnapshot {
	return predicate.UpstreamBalanceSnapshot(func(s *sql.Selector) {
		step := newRunStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.UpstreamBalanceSnapshot) predicate.UpstreamBalanceSnapshot {
	return predicate.UpstreamBalanceSnapshot(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.UpstreamBalanceSnapshot) predicate.UpstreamBalanceSnapshot {
	return predicate.UpstreamBalanceSnapshot(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.UpstreamBalanceSnapshot) predicate.UpstreamBalanceSnapshot {
	return predicate.UpstreamBalanceSnapshot(sql.NotPredicates(p))
}
